import React from 'react'
import {Row, Col, Card, Form} from 'react-bootstrap'
import { Link } from 'react-router-dom'


import { useSelector } from 'react-redux'

import './Indicador.css'


const Indicador = ({header, data, description, colorClass, ies, noop}) => {

    const anoSelecionado = useSelector(state => state.anoSelecionado)

    const Header = (
        <div className='text-center cardTitleContainer'>
            <span className='cardTitle'>{header}</span><br/>
            <div className='cardYear text-black-50'>{ies}</div>
            <span className='cardYear text-black-50'>{anoSelecionado}</span>
        </div>
        
    )

    let dashboardCard = (
        <Link to="/emconstrucao">
            <Card className='dashboardCard'>
                <Card.Body className='indicadorBody'>
                    {Header}
                    <div className="row d-flex align-items-center">
                        <div className="d-flex flex-grow-1 justify-content-center align-items-center">
                            <div className={colorClass + " f-w-300 d-flex flex-grow-1 justify-content-center align-items-center m-b-0 bigNumberContainer"}><span className="bigNumber">{data}</span></div>
                        </div>
                    </div>
                    <h5 className='p-10 d-flex flex-grow-1 justify-content-center align-items-center text-black-50 text-center'>
                        {description}
                    </h5>
                </Card.Body>
            </Card>
        </Link>
    )

    if(noop){
        dashboardCard = (
            <Card>
                <Card.Body className='indicadorBody'>
                    {Header}
                    {noop}
                </Card.Body>
            </Card>

            
        )
    }


    return (
        
        <Col>
            {dashboardCard}
        </Col>
    )
}

export default Indicador