import React from 'react';
import { Link } from 'react-router-dom'


// Componentes
import Indicador from '../../../Components/Indicador'
import indicatorsNames from '../../../store/indicatorsNames'

// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const ComparativoDocentes = ({noOcupation}) => {

    const indicadorClassificacaoCurso = useSelector(state => state.indicadoresIES).indicadorClassificacaoCurso || {mediaInstituicao: null, mediaNacional: null}

    let colorClass = `text-success`
    let description

    description = (
        <div>
            <span >Média nacional: {indicadorClassificacaoCurso.mediaNacional}</span><br/>
            <span className={colorClass}>Acima da média</span>
        </div>
    )

    if(indicadorClassificacaoCurso.mediaInstituicao < indicadorClassificacaoCurso.mediaNacional){
        colorClass = `text-danger`

        description = (
            <div>
                <span >Média nacional: {indicadorClassificacaoCurso.mediaNacional}</span><br/>
                <span className={colorClass}>Abaixo da média</span>
            </div>
        )

    }

    if(indicadorClassificacaoCurso.mediaInstituicao === indicadorClassificacaoCurso.mediaNacional){
        colorClass = `text-dark`

        description = (
            <div>
                <span >Média nacional: {indicadorClassificacaoCurso.mediaNacional}</span><br/>
                <span className={colorClass}>Na média</span>
            </div>
        )

    }

    if(indicadorClassificacaoCurso.mediaInstituicao === null || indicadorClassificacaoCurso.mediaNacional === null){
        colorClass = `text-dark`

        description = (
            <div>
                <span >Curso não encontrado na base do MEC</span><br/>
            </div>
        )

    }
    
    
    
    return (
        <Indicador
            header={indicatorsNames.classificacaoCurso}
            data={`${indicadorClassificacaoCurso.mediaInstituicao !== null ? indicadorClassificacaoCurso.mediaInstituicao:'-'}`}
            description={description}
            colorClass={colorClass}
            noop={noOcupation}
        />
    )
}



export default ComparativoDocentes;