import React from 'react';
import { Link } from 'react-router-dom'


// Componentes
import Indicador from '../../../Components/Indicador'
import indicatorsNames from '../../../store/indicatorsNames'

// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const WagePremium = ({noOcupation}) => {

    const indicadorwagePremium = useSelector(state => state.indicadores).indicadorSalarioMedio || {mediaEnsinoMedio: 0, wagePremium:0, localização:''}
    
    let colorClass = `text-success`
    let description

    description = (
        <div>
            <span>Média salarial de trabalhadores <br/>com Ensino Médio no {indicadorwagePremium.localizacao}:<br/> <b>R$ {new Intl.NumberFormat('bzs', {minimumFractionDigits: 2}).format(indicadorwagePremium.mediaEnsinoMedio)}</b><br/><br/></span> <span className={colorClass}> {indicadorwagePremium.wagePremium - 100}% acima da média</span>
        </div>
    )

    if(indicadorwagePremium.wagePremium < 100){
        colorClass = `text-danger`

        description = (
            <div>
                <span>Média salarial de trabalhadores <br/>com Ensino Médio no {indicadorwagePremium.localizacao}:<br/> <b>R$ {new Intl.NumberFormat('bzs', {minimumFractionDigits: 2}).format(indicadorwagePremium.mediaGraduados)}</b><br/><br/></span> <span className={colorClass}> {100 - indicadorwagePremium.wagePremium}% abaixo da média</span>
            </div>
        )

    }
    
    
    
    return (
        <Indicador
            header={indicatorsNames.wagePremium}
            data={`${indicadorwagePremium.wagePremium}%`}
            description={description}
            colorClass={colorClass}
            noop={noOcupation}
        />
    )
}



export default WagePremium;