import React from 'react';
import { Link } from 'react-router-dom'


// Componentes
import Indicador from '../../../Components/Indicador'
import indicatorsNames from '../../../store/indicatorsNames'

// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const ProbAuto = ({noOcupation}) => {

    const indicadorProbAuto = useSelector(state => state.indicadores).indicadorProbAuto

    let description = (
        <div>
            <span>Probabilidade média entre ocupações selecionadas</span>
        </div>
    )
    
    let colorClass = `text-dark`
    
    return (
        <Indicador
            header={indicatorsNames.probAuto}
            data={`${indicadorProbAuto}%`}
            description={description}
            colorClass={colorClass}
            noop={noOcupation}
        />
    )
}



export default ProbAuto;