import React from 'react';
import { Link } from 'react-router-dom'


// Componentes
import Indicador from '../../../Components/Indicador'
import indicatorsNames from '../../../store/indicatorsNames'

// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const TipoOcupacao = ({noOcupation}) => {

    const indicadorTipoOcupacao = useSelector(state => state.indicadores).indicadorTipoOcupacao || {total: 0, graduados: 0, porcentagem: 0}

    let description = (
        <div>
            <span><b>{indicadorTipoOcupacao.graduados}</b> de <b>{indicadorTipoOcupacao.total}</b> trabalhadores tem, no mínimo, graduação</span>
        </div>
    )
    
    let colorClass = `text-dark`
    
    return (
        <Indicador
            header={indicatorsNames.tipoOcupacao}
            data={`${indicadorTipoOcupacao.porcentagem}%`}
            description={description}
            colorClass={colorClass}
            noop={noOcupation}
        />
    )
}



export default TipoOcupacao;