import React from 'react';
import { Link } from 'react-router-dom'


// Componentes
import Indicador from '../../../Components/Indicador'
import indicatorsNames from '../../../store/indicatorsNames'

// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const SalarioMedio = ({noOcupation}) => {

    const indicadorSalarioMedio = useSelector(state => state.indicadores).indicadorSalarioMedio || {mediaOcupacao: 0}

    let description = (
        <div>
            <span>Salário médio das ocupações relacionadas</span>
        </div>
    )
    
    let colorClass = `text-dark`
    
    return (
        <Indicador
            header={indicatorsNames.salarioMedio}
            data={`R$ ${new Intl.NumberFormat('bzs', {minimumFractionDigits: 2}).format(indicadorSalarioMedio.mediaOcupacao)}`}
            description={description}
            colorClass={colorClass}
            noop={noOcupation}
        />
    )
}



export default SalarioMedio;