import React from 'react';
import { Link } from 'react-router-dom'


// Componentes
import Indicador from '../../../Components/Indicador'
import indicatorsNames from '../../../store/indicatorsNames'

// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const EgressosSaldo = ({noOcupation}) => {

    const indicadorEgressosSaldo = useSelector(state => state.indicadores).indicadorSaldoEmprego || {admitidos: 0, desligados: 0, egressos: 0, egressoVaga:'-'}

    let description = (
        <div>
            <span><b>{indicadorEgressosSaldo.egressos}</b> egressos para <b>{indicadorEgressosSaldo.admitidos - indicadorEgressosSaldo.desligados}</b> vagas criadas</span>
        </div>
    )
    
    let colorClass = `text-dark`
    
    return (
        <Indicador
            header={indicatorsNames.egressosSaldo}
            data={indicadorEgressosSaldo.egressoVaga}
            description={description}
            colorClass={colorClass}
            noop={noOcupation}
        />
    )
}



export default EgressosSaldo;