import React from 'react';
import { Link } from 'react-router-dom'


// Componentes
import Indicador from '../../../Components/Indicador'
import indicatorsNames from '../../../store/indicatorsNames'

// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const SaldoEmprego = ({noOcupation}) => {

    const indicadorSaldoEmprego = useSelector(state => state.indicadores).indicadorSaldoEmprego || {admitidos:null,desligados:null}

    const saldo = indicadorSaldoEmprego.admitidos - indicadorSaldoEmprego.desligados
    
    let description = (
        <div>
            <div className="text-success"><b>Admitidos: {indicadorSaldoEmprego.admitidos}</b></div>
            <div className="text-danger"><b>Desligados: {indicadorSaldoEmprego.desligados}</b></div>
        </div>
    )
    let colorClass = `text-dark`
    
    if(saldo > 0){
        colorClass='text-success'
    }else if(saldo < 0){
        colorClass='text-danger'
    }
   
    return (
        <Indicador
            header={indicatorsNames.saldoEmprego}
            data={indicadorSaldoEmprego.admitidos - indicadorSaldoEmprego.desligados}
            description={description}
            colorClass={colorClass}
            noop={noOcupation}
        />
    )
}



export default SaldoEmprego;