import React from 'react';
import { Link } from 'react-router-dom'


// Componentes
import Indicador from '../../../Components/Indicador'
import indicatorsNames from '../../../store/indicatorsNames'

// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const RankingEmprego = ({noOcupation}) => {

    const indicadorRankingSaldoEmprego = useSelector(state => state.indicadores).indicadorRankingSaldoEmprego || {localizacao:null,qtdOcupacoesLocalizacao:null,rankingMedio:null}

    let description = (
        <div>
            <span><b>{indicadorRankingSaldoEmprego.rankingMedio}°</b> de <b>{indicadorRankingSaldoEmprego.qtdOcupacoesLocalizacao}</b> ocupações no {indicadorRankingSaldoEmprego.localizacao}</span>
        </div>
    )
    let colorClass = `text-dark`
    
    return (
        <Indicador
            header={indicatorsNames.rankingSaldo}
            data={`${indicadorRankingSaldoEmprego.rankingMedio}°`}
            description={description}
            colorClass={colorClass}
            noop={noOcupation}
        />
    )
}



export default RankingEmprego;