import React from 'react';
import { Link } from 'react-router-dom'


// Componentes
import Indicador from '../../../Components/Indicador'
import indicatorsNames from '../../../store/indicatorsNames'

// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const ComparativoSalario = ({noOcupation}) => {

    const indicadorComparativoSalario = useSelector(state => state.indicadores).indicadorSalarioMedio || {mediaGraduados: 0, porcentagem:0, localização:''}
    
    let colorClass = `text-success`
    let description

    description = (
        <div>
            <span>Média salarial de <br/>graduados no {indicadorComparativoSalario.localizacao}:<br/> <b>R$ {new Intl.NumberFormat('bzs', {minimumFractionDigits: 2}).format(indicadorComparativoSalario.mediaGraduados)}</b><br/><br/></span> <span className={colorClass}> {indicadorComparativoSalario.porcentagem - 100}% acima da média</span>
        </div>
    )

    if(indicadorComparativoSalario.porcentagem < 100){
        colorClass = `text-danger`

        description = (
            <div>
                <span>Média salarial de <br/>graduados no {indicadorComparativoSalario.localizacao}:<br/> <b>R$ {new Intl.NumberFormat('bzs', {minimumFractionDigits: 2}).format(indicadorComparativoSalario.mediaGraduados)}</b><br/><br/></span> <span className={colorClass}> {100 - indicadorComparativoSalario.porcentagem}% abaixo da média</span>
            </div>
        )

    }
    
    
    
    return (
        <Indicador
            header={indicatorsNames.comparativoSalario}
            data={`${indicadorComparativoSalario.porcentagem}%`}
            description={description}
            colorClass={colorClass}
            noop={noOcupation}
        />
    )
}



export default ComparativoSalario;