import React from 'react';
import { Link } from 'react-router-dom'


// Componentes
import Indicador from '../../../Components/Indicador'
import indicatorsNames from '../../../store/indicatorsNames'

// Importando do Redux
import { useSelector, useDispatch } from 'react-redux'

const ComparativoDocentes = ({noOcupation}) => {

    const instituicaoSelecionada = useSelector(state => state.instituicaoSelecionada)
    const indicadorComparativoDocente = useSelector(state => state.indicadoresIES).indicadorComparativoDocente || {IESData: {porcentagem: null}, mediaDoutorado: null}

    let colorClass = `text-success`
    let description

    description = (
        <div>
            <span >Média de doutores: {indicadorComparativoDocente.mediaDoutorado}%</span><br/>
            <span className={colorClass}>Acima da média</span>
        </div>
    )

    if(indicadorComparativoDocente.IESData.porcentagem < indicadorComparativoDocente.mediaDoutorado){
        colorClass = `text-danger`

        description = (
            <div>
                <span >Média de doutores: {indicadorComparativoDocente.mediaDoutorado}%</span><br/>
                <span className={colorClass}>Abaixo da média</span>
            </div>
        )

    }
    
    
    
    return (
        <Indicador
            header={indicatorsNames.nivelDocente}
            data={`${indicadorComparativoDocente.IESData.porcentagem}%`}
            description={description}
            colorClass={colorClass}
            noop={noOcupation}
        />
    )
}



export default ComparativoDocentes;